    pid_t p1 = fork();
    if (p1 == 0) {
        close(fd[0]);
        dup2(fd[1], STDOUT_FILENO);
        close(fd[1]);
        printf("alpha\n");
        printf("beta\n");
        printf("gamma\n");
        fflush(stdout);
        _exit(0);
    }

    pid_t p2 = fork();
    if (p2 == 0) {
        close(fd[1]);
        dup2(fd[0], STDIN_FILENO);
        close(fd[0]);
        int count = 0;
        char buf[128];
        while (fgets(buf, sizeof(buf), stdin) != NULL)
            count++;
        printf("Lines: %d\n", count);
        fflush(stdout);
        _exit(0);
    }

    close(fd[0]);
    close(fd[1]);
    wait(NULL);
    wait(NULL);
    return 0;
}

